import React from "react";
import {Link} from 'react-router-dom'

export const Clothes = ({ props }) => {
  console.log(props._id);
  return (
    <div>
      <Link to={'/account/items/'+props._id} className="cursor-pointer">
        <h1>
          Clothes {props.iname} {props.imrp}
        </h1>
        <div className="mt-2 grid grid-cols-3 gap-2 md:grid-cols-4 lg:grid-cols-6">
          {props.photos && (
            <div>
              <img
                className="rounded-2xl w-full object-cover h-32"
                alt="img not found"
                src={"http://localhost:5000/" + props.photos[0]}
              />
            </div>
          )}
        </div>
      </Link>
    </div>
  );
};
